class Solution {
    public long maximumOr(int[] nums, int k) {
        long maxOr = 0;
        for (int i = 0; i < nums.length; i++) {
            maxOr |= nums[i];
        }
        for (int i = 0; i < nums.length; i++) {
            for (int j = 0; j < k; j++) {
                nums[i] *= 2;
                maxOr = Math.max(maxOr, nums[i]);
            }
        }
        return maxOr;
    }
}
